using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext(string? dbName = null)
        {
            var context = CreateInMemoryContext(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructors = new Instructor[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new Department[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3 },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new Course[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 2, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new Student[]
            {
                new Student { ID = 10, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 11, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 12, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01"), Enrollments = new List<Enrollment>() },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var enrollments = new Enrollment[]
            {
                new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 1045, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            var courseAssignments = new CourseAssignment[]
            {
                new CourseAssignment { CourseID = 1050, InstructorID = 3 },
                new CourseAssignment { CourseID = 4022, InstructorID = 2 },
                new CourseAssignment { CourseID = 1045, InstructorID = 2 },
            };
            context.CourseAssignments.AddRange(courseAssignments);
            context.SaveChanges();

            var officeAssignments = new OfficeAssignment[]
            {
                new OfficeAssignment { InstructorID = 2, Location = "Smith 17" },
                new OfficeAssignment { InstructorID = 3, Location = "Gowan 27" },
            };
            context.OfficeAssignments.AddRange(officeAssignments);
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView_WithStudentsList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortsByLastName_Default()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2010
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName); // 2013
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_ResetsPageTo1_WhenNewSearchString()
        {
            _controller.Index(null, null, "test", 5);
            // When searchString is not null, page is set to 1 internally
            // Just verify no exception
        }

        [Fact]
        public void Details_ReturnsStudent_WhenIdIsValid()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_AddsStudentAndRedirects_WhenModelValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateOutOfRange()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1500, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(3, _context.Students.Count()); // Not added
        }

        [Fact]
        public void Edit_Get_ReturnsStudent_WhenIdValid()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentNotExists()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_UpdatesStudentAndRedirects()
        {
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson Updated",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenEnrollmentDateInvalid()
        {
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_ReturnsStudent_WhenIdValid()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentNotExists()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }
    }
}

