        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView_WithDepartmentsList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ReturnsDepartment_WhenIdValid()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentNotExists()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_AddsDepartmentAndRedirects()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = 1
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelInvalid()
        {
            var department = new Department { Name = "Physics", Budget = 200000, StartDate = DateTime.Now };
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsDepartment_WhenIdValid()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentNotExists()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_UpdatesDepartmentAndRedirects()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "English Updated",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelInvalid()
        {
            var department = new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Now };
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsDepartment_WhenIdValid()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentNotExists()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Departments.Count());
        }
    }
}

