using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(2, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count()); // Fakhouri teaches 2 courses
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(2, 1045) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsInstructor_WhenIdValid()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorNotExists()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView_WithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        [Fact]
        public void Create_Post_AddsInstructorAndRedirects()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var created = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Equal(2, _context.CourseAssignments.Count(ca => ca.InstructorID == created.ID));
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelInvalid()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsInstructor_WhenIdValid()
        {
            var result = _controller.Edit(2) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Fakhouri", model.LastName);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsInstructor_WhenIdValid()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorNotExists()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Use instructor 1 who is an administrator of department 1
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Instructors.Count());
            // Verify department's InstructorID was set to null
            var dept = _context.Departments.Find(1);
            Assert.Null(dept!.InstructorID);
        }
    }
}

