using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void Context_CanCreateAndQueryStudents()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Students);
            Assert.Equal("Student", context.Students.First().LastName);
        }

        [Fact]
        public void Context_CanCreateAndQueryCourses()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Test Dept",
                Budget = 100000,
                StartDate = DateTime.Now
            });
            context.SaveChanges();

            context.Courses.Add(new Course
            {
                CourseID = 100,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            });
            context.SaveChanges();

            Assert.Single(context.Courses);
            Assert.Equal("Test Course", context.Courses.First().Title);
        }

        [Fact]
        public void Context_CanCreateAndQueryInstructors()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Instructors.Add(new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Instructors);
        }

        [Fact]
        public void Context_CanCreateAndQueryDepartments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = DateTime.Parse("2020-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Departments);
        }

        [Fact]
        public void Context_CanCreateAndQueryEnrollments()
        {
            using var context = TestHelpers.CreateSeededContext();
            Assert.Equal(3, context.Enrollments.Count());
        }

        [Fact]
        public void Context_CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelpers.CreateSeededContext();
            var assignment = context.CourseAssignments.First();
            Assert.NotNull(assignment);
        }

        [Fact]
        public void Context_OfficeAssignment_IsLinkedToInstructor()
        {
            using var context = TestHelpers.CreateSeededContext();
            var office = context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.NotNull(office.Instructor);
        }

        [Fact]
        public void Context_Student_HasEnrollments()
        {
            using var context = TestHelpers.CreateSeededContext();
            var student = context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 10);
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Context_Department_HasAdministrator()
        {
            using var context = TestHelpers.CreateSeededContext();
            var dept = context.Departments
                .Include(d => d.Administrator)
                .First(d => d.DepartmentID == 1);
            Assert.NotNull(dept.Administrator);
            Assert.Equal("Abercrombie", dept.Administrator.LastName);
        }

        [Fact]
        public void Context_Notification_CanBePersisted()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Notifications.Add(new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Student created",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            });
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }
    }
}

