using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page[0]);
            Assert.Equal(10, page[9]);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(11, page[0]);
            Assert.Equal(20, page[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, page.Count);
            Assert.Equal(21, page[0]);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, page.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_False_OnFirstPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_True_OnSecondPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_True_WhenMorePagesExist()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_False_OnLastPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void PageIndex_IsSetCorrectly()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, page.PageIndex);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };

            var page = new PaginatedList<int>(items, 30, 2, 10);

            Assert.Equal(3, page.Count);
            Assert.Equal(2, page.PageIndex);
            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void EmptySource_ReturnsEmptyPage()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
        }
    }
}

